87	function updateThread(
88	  threads: Thread[],
89	  threadId: ThreadId,
90	  updater: (t: Thread) => Thread,
91	): Thread[] {
92	  let changed = false;
93	  const next = threads.map((t) => {
94	    if (t.id !== threadId) return t;
95	    const updated = updater(t);
96	    if (updated !== t) changed = true;
97	    return updated;
98	  });
99	  return changed ? next : threads;
100	}

1	import { useCallback, useEffect, useSyncExternalStore } from "react";
2	
3	type Theme = "light" | "dark" | "system";
4	type ThemeSnapshot = {
5	  theme: Theme;
6	  systemDark: boolean;
7	};
8	
9	const STORAGE_KEY = "t3code:theme";
10	const MEDIA_QUERY = "(prefers-color-scheme: dark)";
11	
12	let listeners: Array<() => void> = [];
13	let lastSnapshot: ThemeSnapshot | null = null;
14	function emitChange() {
15	  for (const listener of listeners) listener();
16	}
17	
18	function getSystemDark(): boolean {
19	  return window.matchMedia(MEDIA_QUERY).matches;
20	}
21	
22	function getStored(): Theme {
23	  const raw = localStorage.getItem(STORAGE_KEY);
24	  if (raw === "light" || raw === "dark" || raw === "system") return raw;
25	  return "system";
26	}
27	
28	function applyTheme(theme: Theme, suppressTransitions = false) {
29	  if (suppressTransitions) {
30	    document.documentElement.classList.add("no-transitions");
31	  }
32	  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
33	  document.documentElement.classList.toggle("dark", isDark);
34	  if (suppressTransitions) {
35	    // Force a reflow so the no-transitions class takes effect before removal
36	    // oxlint-disable-next-line no-unused-expressions
37	    document.documentElement.offsetHeight;
38	    requestAnimationFrame(() => {
39	      document.documentElement.classList.remove("no-transitions");
40	    });
41	  }
42	}
43	
44	// Apply immediately on module load to prevent flash
45	applyTheme(getStored());
46	
47	function getSnapshot(): ThemeSnapshot {
48	  const theme = getStored();
49	  const systemDark = theme === "system" ? getSystemDark() : false;
50	
51	  if (lastSnapshot && lastSnapshot.theme === theme && lastSnapshot.systemDark === systemDark) {
52	    return lastSnapshot;
53	  }
54	
55	  lastSnapshot = { theme, systemDark };
56	  return lastSnapshot;
57	}
58	
59	function subscribe(listener: () => void): () => void {
60	  listeners.push(listener);
61	
62	  // Listen for system preference changes
63	  const mq = window.matchMedia(MEDIA_QUERY);
64	  const handleChange = () => {
65	    if (getStored() === "system") applyTheme("system", true);
66	    emitChange();
67	  };
68	  mq.addEventListener("change", handleChange);
69	
70	  // Listen for storage changes from other tabs
71	  const handleStorage = (e: StorageEvent) => {
72	    if (e.key === STORAGE_KEY) {
73	      applyTheme(getStored(), true);
74	      emitChange();
75	    }
76	  };
77	  window.addEventListener("storage", handleStorage);
78	
79	  return () => {
80	    listeners = listeners.filter((l) => l !== listener);
81	    mq.removeEventListener("change", handleChange);
82	    window.removeEventListener("storage", handleStorage);
83	  };
84	}
85	
86	export function useTheme() {
87	  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
88	  const theme = snapshot.theme;
89	
90	  const resolvedTheme: "light" | "dark" =
91	    theme === "system" ? (snapshot.systemDark ? "dark" : "light") : theme;
92	
93	  const setTheme = useCallback((next: Theme) => {
94	    localStorage.setItem(STORAGE_KEY, next);
95	    applyTheme(next, true);
96	    emitChange();
97	  }, []);
98	
99	  // Keep DOM in sync on mount/change
100	  useEffect(() => {
101	    applyTheme(theme);
102	  }, [theme]);
103	
104	  return { theme, setTheme, resolvedTheme } as const;
105	}
