25	export function normalizeModelSlug(
26	  model: string | null | undefined,
27	  provider: ProviderKind = "codex",
28	): ModelSlug | null {
29	  if (typeof model !== "string") {
30	    return null;
31	  }
32	
33	  const trimmed = model.trim();
34	  if (!trimmed) {
35	    return null;
36	  }
37	
38	  const aliases = MODEL_SLUG_ALIASES_BY_PROVIDER[provider] as Record<string, ModelSlug>;
