Implementation detail in `useTheme.ts`:

```typescript
let appliedCssPropertyKeys: Set<string> = new Set();

function applyThemeDefinition(theme: ThemeDefinition, suppressTransitions: boolean) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle dark class
  document.documentElement.classList.toggle("dark", theme.mode === "dark");

  // Clear previously applied inline overrides
  for (const key of appliedCssPropertyKeys) {
    document.documentElement.style.removeProperty(`--${key}`);
  }
  appliedCssPropertyKeys.clear();

  // Apply new overrides
  for (const [key, value] of Object.entries(theme.colors)) {
    if (value !== undefined) {
      document.documentElement.style.setProperty(`--${key}`, value);
      appliedCssPropertyKeys.add(key);
    }
  }

  // Font overrides
  if (theme.fontFamily !== undefined) {
    document.body.style.setProperty("font-family", theme.fontFamily);
    appliedCssPropertyKeys.add("__fontFamily");
  } else {
    document.body.style.removeProperty("font-family");
  }
  if (theme.fontSize !== undefined) {
    document.documentElement.style.setProperty("font-size", theme.fontSize);
    appliedCssPropertyKeys.add("__fontSize");
  } else {
    document.documentElement.style.removeProperty("font-size");
  }

  if (suppressTransitions) {
    void document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}
```

