/**
 * Theme definitions and lookup utilities for the T3 Code editor.
 *
 * Each theme declares a `mode` ("light" | "dark") that drives the `.dark` class
 * toggle on the document root, plus an optional `colors` map of CSS custom
 * property overrides (keys are property names without the `--` prefix).
 *
 * Built-in themes whose `colors` map is empty delegate entirely to the default
 * CSS variable values defined in the app stylesheet.
 */

/** CSS custom property names (without `--` prefix) that a theme can override. */
export type ThemeColorKey =
  | "background"
  | "foreground"
  | "card"
  | "card-foreground"
  | "popover"
  | "popover-foreground"
  | "primary"
  | "primary-foreground"
  | "secondary"
  | "secondary-foreground"
  | "muted"
  | "muted-foreground"
  | "accent"
  | "accent-foreground"
  | "destructive"
  | "destructive-foreground"
  | "border"
  | "input"
  | "ring"
  | "info"
  | "info-foreground"
  | "success"
  | "success-foreground"
  | "warning"
  | "warning-foreground";

export interface ThemeDefinition {
  /** Unique stable identifier, e.g. "t3-dark". Used as the localStorage value. */
  readonly id: string;
  /** Human-readable display name, e.g. "T3 Dark". */
  readonly name: string;
  /** Base color-scheme mode. Controls `.dark` class toggle and `resolvedTheme`. */
  readonly mode: "light" | "dark";
  /**
   * CSS variable overrides applied as inline styles on `document.documentElement`.
   * Keys are CSS custom property names WITHOUT the `--` prefix.
   * An empty object means "use the CSS cascade defaults for this mode".
   */
  readonly colors: Partial<Record<ThemeColorKey, string>>;
  /** Optional font family override applied to the document body. */
  readonly fontFamily?: string | undefined;
  /** Optional base font size override (e.g. "14px", "0.875rem"). */
  readonly fontSize?: string | undefined;
}

/** The theme ID used when no preference has been persisted. */
export const DEFAULT_THEME_ID = "t3-dark";

const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    mode: "dark",
    colors: {},
  },
  {
    id: "t3-light",
    name: "T3 Light",
    mode: "light",
    colors: {},
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    mode: "dark",
    colors: {
      background: "#0a0a14",
      foreground: "#c8c8d8",
      card: "#0f0f1c",
      "card-foreground": "#c8c8d8",
      popover: "#0f0f1c",
      "popover-foreground": "#c8c8d8",
      primary: "oklch(0.65 0.25 270)",
      "primary-foreground": "#ffffff",
      secondary: "rgba(255, 255, 255, 0.04)",
      "secondary-foreground": "#c8c8d8",
      muted: "rgba(255, 255, 255, 0.04)",
      "muted-foreground": "#7a7a8e",
      accent: "rgba(255, 255, 255, 0.06)",
      "accent-foreground": "#c8c8d8",
      destructive: "#ef5a5a",
      "destructive-foreground": "#f87171",
      border: "rgba(255, 255, 255, 0.06)",
      input: "rgba(255, 255, 255, 0.08)",
      ring: "oklch(0.65 0.25 270)",
      info: "#3b82f6",
      "info-foreground": "#60a5fa",
      success: "#10b981",
      "success-foreground": "#34d399",
      warning: "#f59e0b",
      "warning-foreground": "#fbbf24",
    },
  },
];

const themeById = new Map<string, ThemeDefinition>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

/** Return the full list of built-in themes. */
export function listThemes(): readonly ThemeDefinition[] {
  return BUILT_IN_THEMES;
}

/** Look up a theme by its unique ID. Returns `undefined` when not found. */
export function getTheme(id: string): ThemeDefinition | undefined {
  return themeById.get(id);
}

