import { describe, expect, it } from "vitest";
import { DEFAULT_THEME_ID, getTheme, listThemes } from "./themes";

describe("listThemes", () => {
  it("returns at least 3 built-in themes", () => {
    expect(listThemes().length).toBeGreaterThanOrEqual(3);
  });

  it("returns themes with unique ids", () => {
    const ids = listThemes().map((t) => t.id);
    expect(new Set(ids).size).toBe(ids.length);
  });

  it("returns themes where every mode is light or dark", () => {
    for (const theme of listThemes()) {
      expect(["light", "dark"]).toContain(theme.mode);
    }
  });
});

describe("getTheme", () => {
  it("returns t3-dark with mode dark and empty colors", () => {
    const theme = getTheme("t3-dark");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("dark");
    expect(Object.keys(theme!.colors)).toHaveLength(0);
  });

  it("returns t3-light with mode light and empty colors", () => {
    const theme = getTheme("t3-light");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("light");
    expect(Object.keys(theme!.colors)).toHaveLength(0);
  });

  it("returns t3-midnight with mode dark and non-empty colors", () => {
    const theme = getTheme("t3-midnight");
    expect(theme).toBeDefined();
    expect(theme!.mode).toBe("dark");
    expect(Object.keys(theme!.colors).length).toBeGreaterThan(0);
  });

  it("returns undefined for unknown theme id", () => {
    expect(getTheme("nonexistent")).toBeUndefined();
  });
});

describe("DEFAULT_THEME_ID", () => {
  it("matches one of the built-in theme ids", () => {
    const ids = listThemes().map((t) => t.id);
    expect(ids).toContain(DEFAULT_THEME_ID);
  });
});

