const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/** Maps legacy stored values ("light"/"dark") to theme IDs. */
const LEGACY_VALUE_MAP: Record<string, string> = {
  light: "t3-light",
  dark: "t3-dark",
};

// ---------------------------------------------------------------------------
// Module-level external store (same pattern as before)
// ---------------------------------------------------------------------------

type ThemeSnapshot = {
  themeId: string; // raw stored value: "system" | theme ID
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/** Read the persisted preference, migrating legacy values transparently. */
function getStored(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === null || raw === "system") return "system";
  if (raw in LEGACY_VALUE_MAP) return LEGACY_VALUE_MAP[raw]!;
  return raw;
}

/** Resolve the stored preference to a concrete ThemeDefinition. */
function resolveTheme(stored: string): ThemeDefinition {
  if (stored === "system") {
    const id = getSystemDark() ? "t3-dark" : "t3-light";
    return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
  }
  return getTheme(stored) ?? getTheme(DEFAULT_THEME_ID)!;
}

// ---------------------------------------------------------------------------
// CSS variable application
// ---------------------------------------------------------------------------

/** Tracks which CSS properties were set by the last theme application. */
let appliedPropertyKeys = new Set<string>();
let appliedFontFamily = false;
let appliedFontSize = false;

function applyThemeDefinition(theme: ThemeDefinition, suppressTransitions: boolean): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class based on theme mode
  document.documentElement.classList.toggle("dark", theme.mode === "dark");

  // Clear previously applied inline overrides
  for (const key of appliedPropertyKeys) {
    document.documentElement.style.removeProperty(`--${key}`);
  }
  appliedPropertyKeys = new Set<string>();

  // Apply new color overrides
  for (const [key, value] of Object.entries(theme.colors)) {
    if (value !== undefined) {
      document.documentElement.style.setProperty(`--${key}`, value);
      appliedPropertyKeys.add(key);
    }
  }

  // Font overrides
  if (theme.fontFamily !== undefined) {
    document.body.style.setProperty("font-family", theme.fontFamily);
    appliedFontFamily = true;
  } else if (appliedFontFamily) {
    document.body.style.removeProperty("font-family");
    appliedFontFamily = false;
  }

  if (theme.fontSize !== undefined) {
    document.documentElement.style.setProperty("font-size", theme.fontSize);
    appliedFontSize = true;
  } else if (appliedFontSize) {
    document.documentElement.style.removeProperty("font-size");
    appliedFontSize = false;
  }

