applyThemeDefinition(resolveTheme(getStored()), false);

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const themeId = getStored();
  const systemDark = themeId === "system" ? getSystemDark() : false;

  if (lastSnapshot && lastSnapshot.themeId === themeId && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") {
      applyThemeDefinition(resolveTheme("system"), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyThemeDefinition(resolveTheme(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

const availableThemes = listThemes();

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const themeId = snapshot.themeId;

  const activeTheme = resolveTheme(themeId);
  const resolvedTheme: "light" | "dark" = activeTheme.mode;

  const setTheme = useCallback((next: string) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyThemeDefinition(resolveTheme(next), true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyThemeDefinition(activeTheme, false);
  }, [activeTheme]);

  return {
    /** Raw stored preference: `"system"` or a theme ID like `"t3-dark"`. */
    theme: themeId,
    /** Update the stored theme preference. Accepts `"system"` or any theme ID. */
    setTheme,
    /** The resolved color-scheme mode — always `"light"` or `"dark"`. */
    resolvedTheme,
    /** The fully resolved ThemeDefinition object for the active theme. */
    activeTheme,
    /** All available built-in themes. */
    availableThemes,
  } as const;
}

