import { MonitorIcon } from "lucide-react";
import type { ThemeDefinition } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";

/**
 * Hardcoded preview colors for built-in themes whose `colors` map is empty.
 * These match the CSS defaults defined in `index.css`.
 */
const SWATCH_PREVIEWS: Record<string, { bg: string; fg: string; primary: string; accent: string; border: string }> = {
  "t3-light": {
    bg: "#ffffff",
    fg: "#262626",
    primary: "oklch(0.488 0.217 264)",
    accent: "#f5f5f5",
    border: "rgba(0, 0, 0, 0.08)",
  },
  "t3-dark": {
    bg: "#0d0d0d",
    fg: "#f5f5f5",
    primary: "oklch(0.588 0.217 264)",
    accent: "#1a1a1a",
    border: "rgba(255, 255, 255, 0.06)",
  },
};

function getPreviewColors(theme: ThemeDefinition): {
  bg: string;
  fg: string;
  primary: string;
  accent: string;
  border: string;
} {
  const cached = SWATCH_PREVIEWS[theme.id];
  if (cached) return cached;
  return {
    bg: theme.colors.background ?? (theme.mode === "dark" ? "#0d0d0d" : "#ffffff"),
    fg: theme.colors.foreground ?? (theme.mode === "dark" ? "#f5f5f5" : "#262626"),
    primary: theme.colors.primary ?? "oklch(0.55 0.22 264)",
    accent: theme.colors.accent ?? (theme.mode === "dark" ? "#1a1a1a" : "#f5f5f5"),
    border: theme.colors.border ?? (theme.mode === "dark" ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.08)"),
  };
}

function ThemeSwatch({
  theme,
  selected,
  onSelect,
}: {
  theme: ThemeDefinition;
  selected: boolean;
  onSelect: () => void;
}) {
  const preview = getPreviewColors(theme);

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex flex-col items-start gap-2.5 rounded-lg border px-3 py-2.5 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onSelect}
    >
      {/* Color preview strip */}
      <div
        className="flex w-full items-center gap-1.5 rounded-md border p-1.5"
        style={{ backgroundColor: preview.bg, borderColor: preview.border }}
      >
        <span
          className="size-4 shrink-0 rounded-full"
          style={{ backgroundColor: preview.primary }}
        />
        <span
          className="size-4 shrink-0 rounded-full"
          style={{ backgroundColor: preview.accent }}
        />
        <span
          className="size-4 shrink-0 rounded-full"
          style={{ backgroundColor: preview.fg, opacity: 0.6 }}
        />
        <span
          className="size-4 shrink-0 rounded-full border"
          style={{ backgroundColor: preview.bg, borderColor: preview.border }}
        />
      </div>

      <div className="flex w-full items-center justify-between gap-2">
        <span className="text-sm font-medium">{theme.name}</span>
        {selected ? (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes, resolvedTheme } = useTheme();

  return (
    <div className="space-y-3">
      {/* System preference option */}
      <button
        type="button"
        role="radio"
        aria-checked={theme === "system"}
        className={`flex w-full items-center justify-between gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
          theme === "system"
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent"
        }`}
        onClick={() => setTheme("system")}
      >
        <span className="flex items-center gap-2.5">
          <MonitorIcon className="size-4 shrink-0" />
          <span className="flex flex-col">
            <span className="text-sm font-medium">System</span>
            <span className="text-xs">Match your OS appearance setting.</span>
          </span>
        </span>
        {theme === "system" ? (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </button>

      {/* Theme grid */}
      <div className="grid grid-cols-3 gap-2" role="radiogroup" aria-label="Theme selection">
        {availableThemes.map((t) => (
          <ThemeSwatch
            key={t.id}
            theme={t}
            selected={theme === t.id}
            onSelect={() => setTheme(t.id)}
          />
        ))}
      </div>

      <p className="text-xs text-muted-foreground">
        Active theme: <span className="font-medium text-foreground">{resolvedTheme}</span>
      </p>
    </div>
  );
}

